
  create table "public"."community_comments" (
    "id" bigint generated by default as identity not null,
    "post_id" bigint not null,
    "sales_id" bigint not null,
    "body" text not null,
    "created_at" timestamp with time zone not null default now()
      );


alter table "public"."community_comments" enable row level security;


  create table "public"."community_posts" (
    "id" bigint generated by default as identity not null,
    "sales_id" bigint not null,
    "title" text not null,
    "body" text not null,
    "created_at" timestamp with time zone not null default now(),
    "updated_at" timestamp with time zone not null default now()
      );


alter table "public"."community_posts" enable row level security;

CREATE UNIQUE INDEX community_comments_pkey ON public.community_comments USING btree (id);

CREATE INDEX community_comments_post_id_idx ON public.community_comments USING btree (post_id);

CREATE INDEX community_comments_sales_id_idx ON public.community_comments USING btree (sales_id);

CREATE UNIQUE INDEX community_posts_pkey ON public.community_posts USING btree (id);

CREATE INDEX community_posts_sales_id_idx ON public.community_posts USING btree (sales_id);

alter table "public"."community_comments" add constraint "community_comments_pkey" PRIMARY KEY using index "community_comments_pkey";

alter table "public"."community_posts" add constraint "community_posts_pkey" PRIMARY KEY using index "community_posts_pkey";

alter table "public"."community_comments" add constraint "community_comments_post_id_fkey" FOREIGN KEY (post_id) REFERENCES public.community_posts(id) ON UPDATE CASCADE ON DELETE CASCADE not valid;

alter table "public"."community_comments" validate constraint "community_comments_post_id_fkey";

alter table "public"."community_comments" add constraint "community_comments_sales_id_fkey" FOREIGN KEY (sales_id) REFERENCES public.sales(id) ON UPDATE CASCADE ON DELETE CASCADE not valid;

alter table "public"."community_comments" validate constraint "community_comments_sales_id_fkey";

alter table "public"."community_posts" add constraint "community_posts_sales_id_fkey" FOREIGN KEY (sales_id) REFERENCES public.sales(id) ON UPDATE CASCADE ON DELETE CASCADE not valid;

alter table "public"."community_posts" validate constraint "community_posts_sales_id_fkey";

