  create policy "Community comments delete author or admin"
  on "public"."community_comments"
  as permissive
  for delete
  to authenticated
using ((public.is_admin() OR (sales_id = ( SELECT sales.id
   FROM public.sales
  WHERE (sales.user_id = auth.uid())))));



  create policy "Community comments insert as self"
  on "public"."community_comments"
  as permissive
  for insert
  to authenticated
with check (((sales_id IS NULL) OR (sales_id = ( SELECT sales.id
   FROM public.sales
  WHERE (sales.user_id = auth.uid()))) OR public.is_admin()));



  create policy "Community comments read all"
  on "public"."community_comments"
  as permissive
  for select
  to authenticated
using (true);



  create policy "Community comments update author or admin"
  on "public"."community_comments"
  as permissive
  for update
  to authenticated
using ((public.is_admin() OR (sales_id = ( SELECT sales.id
   FROM public.sales
  WHERE (sales.user_id = auth.uid())))))
with check ((public.is_admin() OR (sales_id = ( SELECT sales.id
   FROM public.sales
  WHERE (sales.user_id = auth.uid())))));



